import java.util.Scanner;

public class SafeBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = 10; // Buffer size
        char[] buffer = new char[bufferSize];

        // Copy user input into the buffer, limiting to buffer size
        int length = Math.min(input.length(), bufferSize);
        input.getChars(0, length, buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
